// // This module implements a 3-input multiplexer where the output is the logical OR of inputs a and b when sel is 2.
module mux_3input_behavioral (
  input [1:0] sel,
  input a,
  input b,
  output reg out
);

  always @(*) begin
    if(sel == 0)
      out = a;
    else if(sel == 1)
      out = b;
    else if(sel == 2)
      out = a & b;
  end

endmodule
